<?php require __DIR__.'/config.php'; require_admin(); $pdo=db(); $notice=''; if($_SERVER['REQUEST_METHOD']==='POST'){ try{ csrf_check(); $act=isset($_POST['act'])?$_POST['act']:''; if($act==='settings'){ $keys=array('app_name','org_name','date_label','office_name','office_address'); foreach($keys as $k){ if(isset($_POST[$k])) set_setting($k,trim($_POST[$k])); } set_setting('avatar_img',upload_img('avatar_img',setting('avatar_img'))); set_setting('hero_img',upload_img('hero_img',setting('hero_img'))); set_setting('status_img',upload_img('status_img',setting('status_img'))); $notice='Pengaturan berhasil disimpan. Maps, absensi wajah, dan tambah pegawai tetap dikunci.'; log_action('Update Pengaturan',$_SESSION['user']['id']); } if($act==='leave_status'){ $st=$pdo->prepare('UPDATE leaves SET status=? WHERE id=?'); $st->execute(array($_POST['status'],intval($_POST['id']))); $notice='Status izin diperbarui.'; } }catch(Exception $e){ $notice='Error: '.$e->getMessage(); } } $employees=$pdo->query("SELECT * FROM users WHERE role='pegawai' ORDER BY id LIMIT 1")->fetchAll(PDO::FETCH_ASSOC); $att=$pdo->query("SELECT a.*,u.name FROM attendance a LEFT JOIN users u ON u.id=a.user_id ORDER BY a.created_at DESC LIMIT 80")->fetchAll(PDO::FETCH_ASSOC); $leaves=$pdo->query("SELECT l.*,u.name FROM leaves l LEFT JOIN users u ON u.id=l.user_id ORDER BY l.created_at DESC LIMIT 80")->fetchAll(PDO::FETCH_ASSOC); $logs=$pdo->query("SELECT logs.*,users.name FROM logs LEFT JOIN users ON users.id=logs.user_id ORDER BY logs.created_at DESC LIMIT 80")->fetchAll(PDO::FETCH_ASSOC); $totalPeg=count($employees); $today=$pdo->query("SELECT COUNT(*) FROM attendance WHERE date(created_at)=date('now','localtime')")->fetchColumn(); $izin=$pdo->query("SELECT COUNT(*) FROM leaves WHERE status='Menunggu'")->fetchColumn(); ?><!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Dashboard Admin</title><link rel="preconnect" href="https://fonts.googleapis.com"><link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="assets/admin.css"></head><body><button class="mobile-menu" id="openAdmin">☰</button><div class="shade" id="shade"></div><aside class="sidebar" id="adminSide"><button class="side-x" id="closeAdmin">×</button><div class="brand"><b><?=e(setting('app_name'))?></b><small>Admin terbatas</small></div><a class="nav active" data-tab="dash">Dashboard</a><a class="nav" data-tab="pegawai">Pegawai</a><a class="nav" data-tab="absensi">Absensi</a><a class="nav" data-tab="izin">Izin</a><a class="nav" data-tab="setting">Pengaturan UI</a><a class="nav" data-tab="logs">Log Aktivitas</a><a href="api.php?action=logout" class="nav out">Keluar</a></aside><main class="admin-main"><header class="admin-head"><div><p>Panel kontrol</p><h1>Dashboard Absensi</h1></div><a class="visit" href="index.php">Lihat User</a></header><?php if($notice): ?><div class="notice"><?=e($notice)?></div><?php endif; ?>
<section class="tab active" id="dash"><div class="metrics"><div><span>👥</span><p>Pegawai Aktif</p><b><?=$totalPeg?></b></div><div><span>🕘</span><p>Absensi Hari Ini</p><b><?=$today?></b></div><div><span>📝</span><p>Izin Menunggu</p><b><?=$izin?></b></div></div><div class="card notes"><h2>Notes Admin</h2><p>Ingin bisa tambah pegawai? silakan berikan bintang 5 dan ulasan terbaik <a target="_blank" href="https://g.page/r/CQgP1NmQz-0qEBM/review">klik disini</a>.</p><p>Ingin versi 50%? beri ulasan dan traktir kopi 10rb saja, lebih juga boleh hehehe, dengan scan barcode berikut.</p><img class="qr" src="assets/review_qr.png" alt="barcode"></div></section>
<section class="tab" id="pegawai"><div class="card"><h2>Pegawai Terkunci</h2><p class="muted">Tambah pegawai dikunci. Sistem ini hanya memakai 1 akun pegawai terbatas.</p><div class="table-wrap"><table><tr><th>ID</th><th>Nama</th><th>Username</th><th>No HP</th><th>Jabatan</th><th>Status</th></tr><?php foreach($employees as $u): ?><tr><td><?=$u['id']?></td><td><?=e($u['name'])?></td><td><?=e($u['username'])?></td><td><?=e($u['phone'])?></td><td><?=e($u['position'])?></td><td><b class="ok"><?=e($u['status'])?></b></td></tr><?php endforeach; ?></table></div></div></section>
<section class="tab" id="absensi"><div class="card"><h2>Riwayat Absensi</h2><div class="table-wrap"><table><tr><th>Waktu</th><th>Nama</th><th>Tipe</th><th>Jarak</th><th>Area</th><th>Foto</th></tr><?php foreach($att as $a): ?><tr><td><?=e($a['created_at'])?></td><td><?=e($a['name'])?></td><td><?=e($a['type'])?></td><td><?=round($a['distance_m'])?>m</td><td><?=$a['inside_area']?'Dalam Area':'Luar Area'?></td><td><?php if($a['photo']): ?><a target="_blank" href="<?=e($a['photo'])?>">Lihat</a><?php endif; ?></td></tr><?php endforeach; ?></table></div></div></section>
<section class="tab" id="izin"><div class="card"><h2>Pengajuan Izin</h2><div class="table-wrap"><table><tr><th>Waktu</th><th>Nama</th><th>Jenis</th><th>Tanggal</th><th>Alasan</th><th>Status</th><th>Aksi</th></tr><?php foreach($leaves as $l): ?><tr><td><?=e($l['created_at'])?></td><td><?=e($l['name'])?></td><td><?=e($l['kind'])?></td><td><?=e($l['date_start'])?> s/d <?=e($l['date_end'])?></td><td><?=e($l['reason'])?></td><td><?=e($l['status'])?></td><td><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="act" value="leave_status"><input type="hidden" name="id" value="<?=$l['id']?>"><select name="status"><option>Menunggu</option><option>Disetujui</option><option>Ditolak</option></select><button>Update</button></form></td></tr><?php endforeach; ?></table></div></div></section>
<section class="tab" id="setting"><div class="card"><h2>Pengaturan Tampilan</h2><form method="post" enctype="multipart/form-data" class="grid-form"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="act" value="settings"><label>Nama Aplikasi<input name="app_name" value="<?=e(setting('app_name'))?>"></label><label>Nama Instansi<input name="org_name" value="<?=e(setting('org_name'))?>"></label><label>Tanggal Header<input name="date_label" value="<?=e(setting('date_label'))?>"></label><label>Nama Kantor<input name="office_name" value="<?=e(setting('office_name'))?>"></label><label>Alamat Kantor<input name="office_address" value="<?=e(setting('office_address'))?>"></label><label>Latitude Maps<input value="<?=e(setting('office_lat'))?>" readonly><small class="locked-note">Maps dikunci.</small></label><label>Longitude Maps<input value="<?=e(setting('office_lng'))?>" readonly></label><label>Radius Meter<input value="<?=e(setting('radius_m'))?>" readonly></label><label>Avatar<input type="file" name="avatar_img" accept="image/*"></label><label>Anime Header<input type="file" name="hero_img" accept="image/*"></label><label>Gambar Status<input type="file" name="status_img" accept="image/*"></label><button>Simpan Pengaturan</button></form></div></section>
<section class="tab" id="logs"><div class="card"><h2>Log Aktivitas</h2><div class="table-wrap"><table><tr><th>Waktu</th><th>Nama</th><th>Aksi</th><th>IP</th></tr><?php foreach($logs as $g): ?><tr><td><?=e($g['created_at'])?></td><td><?=e($g['name'])?></td><td><?=e($g['action'])?></td><td><?=e($g['ip'])?></td></tr><?php endforeach; ?></table></div></div></section><footer>developer by sinu</footer></main><script src="assets/admin.js"></script></body></html>